21201           auto *AltCI = cast<CmpInst>(E->getAltOp());
21202           CmpInst::Predicate AltPred = AltCI->getPredicate();
21203           V1 = Builder.CreateCmp(AltPred, LHS, RHS);
21204         } else {
21205           if (LHS->getType()->isIntOrIntVectorTy() && ScalarTy->isIntegerTy()) {
21206             unsigned SrcBWSz = DL->getTypeSizeInBits(
21207                 cast<VectorType>(LHS->getType())->getElementType());
21208             unsigned BWSz = DL->getTypeSizeInBits(ScalarTy);
21209             if (BWSz <= SrcBWSz) {
21210               if (BWSz < SrcBWSz)
21211                 LHS = Builder.CreateIntCast(LHS, VecTy, It->second.first);
21212               assert(LHS->getType() == VecTy &&
21213                      "Expected same type as operand.");
21214               if (auto *I = dyn_cast<Instruction>(LHS))
21215                 LHS = ::propagateMetadata(I, E->Scalars);
21216               LHS = FinalShuffle(LHS, E);
21217               E->VectorizedValue = LHS;
21218               ++NumVectorInstructions;
21219               return LHS;
21220             }
21221           }
21222           V0 = Builder.CreateCast(
21223               static_cast<Instruction::CastOps>(E->getOpcode()), LHS, VecTy);
21224           V1 = Builder.CreateCast(
21225               static_cast<Instruction::CastOps>(E->getAltOpcode()), LHS, VecTy);
21226         }
21227         // Add V0 and V1 to later analysis to try to find and remove matching
21228         // instruction, if any.
21229         for (Value *V : {V0, V1}) {
21230           if (auto *I = dyn_cast<Instruction>(V)) {
21231             GatherShuffleExtractSeq.insert(I);
21232             CSEBlocks.insert(I->getParent());
21233           }
21234         }
21235 
21236         // Create shuffle to take alternate operations from the vector.
21237         // Also, gather up main and alt scalar ops to propagate IR flags to
21238         // each vector operation.
21239         ValueList OpScalars, AltScalars;
21240         SmallVector<int> Mask;
21241         E->buildAltOpShuffleMask(
21242             [E, this](Instruction *I) {
21243               assert(E->getMatchingMainOpOrAltOp(I) &&
21244                      "Unexpected main/alternate opcode");
21245               return isAlternateInstruction(I, E->getMainOp(), E->getAltOp(),
21246                                             *TLI);
21247             },
21248             Mask, &OpScalars, &AltScalars);
21249 
21250         propagateIRFlags(V0, OpScalars, E->getMainOp(), It == MinBWs.end());
21251         propagateIRFlags(V1, AltScalars, E->getAltOp(), It == MinBWs.end());
21252         auto DropNuwFlag = [&](Value *Vec, unsigned Opcode) {
21253           // Drop nuw flags for abs(sub(commutative), true).
21254           if (auto *I = dyn_cast<Instruction>(Vec);
21255               I && Opcode == Instruction::Sub && !MinBWs.contains(E) &&
21256               any_of(E->Scalars, [E](Value *V) {
21257                 if (isa<PoisonValue>(V))
21258                   return false;
21259                 if (E->hasCopyableElements() && E->isCopyableElement(V))
21260                   return false;
21261                 auto *IV = cast<Instruction>(V);
21262                 return IV->getOpcode() == Instruction::Sub && isCommutative(IV);
21263               }))
21264             I->setHasNoUnsignedWrap(/*b=*/false);
21265         };
21266         DropNuwFlag(V0, E->getOpcode());
21267         DropNuwFlag(V1, E->getAltOpcode());
21268 
21269         if (auto *VecTy = dyn_cast<FixedVectorType>(ScalarTy)) {
21270           assert(SLPReVec && "FixedVectorType is not expected.");
21271           transformScalarShuffleIndiciesToVector(VecTy->getNumElements(), Mask);
21272         }
21273         V = Builder.CreateShuffleVector(V0, V1, Mask);
21274         if (auto *I = dyn_cast<Instruction>(V)) {
21275           V = ::propagateMetadata(I, E->Scalars);
21276           GatherShuffleExtractSeq.insert(I);
21277           CSEBlocks.insert(I->getParent());
21278         }
21279       }
21280 
21281       E->VectorizedValue = V;
21282       ++NumVectorInstructions;
21283 
21284       return V;
21285     }
21286     case TreeEntry::ReducedBitcast:
21287     case TreeEntry::ReducedBitcastBSwap: {
21288       assert(UserIgnoreList && "Expected reduction operations only.");
21289       setInsertPointAfterBundle(E);
21290       TreeEntry *ZExt = getOperandEntry(E, /*Idx=*/0);
21291       ZExt->VectorizedValue = PoisonValue::get(getWidenedType(
21292           ZExt->getMainOp()->getType(), ZExt->getVectorFactor()));
21293       TreeEntry *Const = getOperandEntry(E, /*Idx=*/1);
21294       Const->VectorizedValue = PoisonValue::get(getWidenedType(
21295           Const->Scalars.front()->getType(), Const->getVectorFactor()));
21296       Value *Op = vectorizeOperand(ZExt, 0);
21297       // Set the scalar type properly to avoid casting to the extending type.
21298       ScalarTy = cast<CastInst>(ZExt->getMainOp())->getSrcTy();
